import { Routes } from '@angular/router';
import { authGuard } from './core/guards/auth.guard';
import { roleGuard } from './core/guards/role.guard';
import { FlowRoute } from './flow-meta';

// `data.flow` is the single source of truth for the user-flow graph AND the runtime navbar.
// Every navigable UI state is reachable by URL (hash routing). Schedule filters live in
// `?when=` query params; create dialogs are dedicated `/new` routes.
export const routes: Routes = ([
  { path: '', redirectTo: 'home', pathMatch: 'full' },

  {
    path: 'login',
    loadComponent: () => import('./pages/login/login.component').then((m) => m.LoginComponent),
    data: { flow: { flowId: 'login', node: 'login', entry: true, edgesTo: ['home', 'signup'], label: 'Login' } },
  },
  {
    path: 'signup',
    loadComponent: () => import('./pages/signup/signup.component').then((m) => m.SignupComponent),
    data: { flow: { flowId: 'signup', node: 'signup', edgesTo: ['home', 'login'], label: 'Sign up' } },
  },

  {
    path: '',
    loadComponent: () => import('./shared/layout.component').then((m) => m.LayoutComponent),
    canActivate: [authGuard],
    children: [
      {
        path: 'home',
        loadComponent: () => import('./pages/home/home.component').then((m) => m.HomeComponent),
        data: { flow: { flowId: 'home', node: 'home', showInNavbar: true, label: 'Home', scope: 'all',
          edgesTo: ['schedule', 'boats', 'members', 'conditions', 'practice-detail'] } },
      },

      {
        path: 'schedule',
        loadComponent: () => import('./pages/schedule/schedule.component').then((m) => m.ScheduleComponent),
        data: { flow: { flowId: 'schedule', node: 'schedule', showInNavbar: true, label: 'Schedule', scope: 'all',
          edgesTo: ['practice-detail', 'practice-new', 'home'] } },
      },
      {
        path: 'practices/new',
        loadComponent: () => import('./pages/practice-form/practice-form.component').then((m) => m.PracticeFormComponent),
        canActivate: [roleGuard], data: { roles: ['coach'],
          flow: { flowId: 'practice-new', node: 'practice-new', label: 'New practice', scope: 'coach', edgesTo: ['schedule'] } },
      },
      {
        path: 'practices/:id',
        loadComponent: () => import('./pages/practice-detail/practice-detail.component').then((m) => m.PracticeDetailComponent),
        data: { flow: { flowId: 'practice-detail', node: 'practice-detail', label: 'Practice detail', scope: 'all',
          edgesTo: ['schedule', 'practice-edit', 'boats'] } },
      },
      {
        path: 'practices/:id/edit',
        loadComponent: () => import('./pages/practice-form/practice-form.component').then((m) => m.PracticeFormComponent),
        canActivate: [roleGuard], data: { roles: ['coach'],
          flow: { flowId: 'practice-edit', node: 'practice-edit', label: 'Edit practice', scope: 'coach', edgesTo: ['practice-detail'] } },
      },

      {
        path: 'boats',
        loadComponent: () => import('./pages/boats/boats.component').then((m) => m.BoatsComponent),
        data: { flow: { flowId: 'boats', node: 'boats', showInNavbar: true, label: 'Boats', scope: 'all',
          edgesTo: ['boat-new', 'boat-detail', 'home'] } },
      },
      {
        path: 'boats/new',
        loadComponent: () => import('./pages/boat-form/boat-form.component').then((m) => m.BoatFormComponent),
        canActivate: [roleGuard], data: { roles: ['coach'],
          flow: { flowId: 'boat-new', node: 'boat-new', label: 'New boat', scope: 'coach', edgesTo: ['boats'] } },
      },
      {
        path: 'boats/:id',
        loadComponent: () => import('./pages/boat-form/boat-form.component').then((m) => m.BoatFormComponent),
        canActivate: [roleGuard], data: { roles: ['coach'],
          flow: { flowId: 'boat-detail', node: 'boat-detail', label: 'Edit boat', scope: 'coach', edgesTo: ['boats'] } },
      },

      {
        path: 'members',
        loadComponent: () => import('./pages/members/members.component').then((m) => m.MembersComponent),
        data: { flow: { flowId: 'members', node: 'members', showInNavbar: true, label: 'Members', scope: 'all',
          edgesTo: ['member-detail', 'home'] } },
      },
      {
        path: 'members/:id',
        loadComponent: () => import('./pages/member-detail/member-detail.component').then((m) => m.MemberDetailComponent),
        data: { flow: { flowId: 'member-detail', node: 'member-detail', label: 'Member detail', scope: 'all', edgesTo: ['members'] } },
      },

      {
        path: 'conditions',
        loadComponent: () => import('./pages/conditions/conditions.component').then((m) => m.ConditionsComponent),
        data: { flow: { flowId: 'conditions', node: 'conditions', showInNavbar: true, label: 'Conditions', scope: 'all',
          edgesTo: ['condition-new', 'home'] } },
      },
      {
        path: 'conditions/new',
        loadComponent: () => import('./pages/condition-new/condition-new.component').then((m) => m.ConditionNewComponent),
        data: { flow: { flowId: 'condition-new', node: 'condition-new', label: 'Log conditions', scope: 'all', edgesTo: ['conditions'] } },
      },

      {
        path: 'admin/settings',
        loadComponent: () => import('./pages/admin-settings/admin-settings.component').then((m) => m.AdminSettingsComponent),
        canActivate: [roleGuard], data: { roles: ['coach'],
          flow: { flowId: 'admin-settings', node: 'admin-settings', showInNavbar: true, label: 'Settings', scope: 'coach', edgesTo: ['home'] } },
      },
    ],
  },

  { path: '**', redirectTo: 'home' },
] satisfies FlowRoute[]) as Routes;
